                        <StatBox label="CRT" value={`${derived.critChance}%`} icon={<Target className="w-2 h-2" />} color="text-red-400" />
                        <StatBox label="ACC" value={derived.accuracy} icon={<Crosshair className="w-2 h-2" />} />
                        <StatBox label="EVA" value={derived.evasion} icon={<Wind className="w-2 h-2" />} />
                    </div>
                </div>
            ) : (
                <div onClick={onSelect} className="h-full border-2 border-dashed border-stone-800 rounded-lg flex flex-col items-center justify-center gap-1 text-stone-600 hover:text-stone-400 hover:border-stone-600 transition-all hover:bg-stone-800/30 cursor-pointer min-h-[100px] md:min-h-[140px]"><User className="w-6 h-6 md:w-8 md:h-8 opacity-20" /><span className="text-[8px] md:text-[10px] font-black uppercase tracking-widest">Assign Slot</span></div>
            )}
        </div>
    );
};

