    analysis: string[];
}

export interface BulkReport {
    rounds: number;
    winA: number;
    winB: number;
    avgAtksA: number;
    avgAtksB: number;
    avgCritsA: number;
    avgCritsB: number;
    avgEvasionsA: number;
    avgEvasionsB: number;
}

export interface SimulationHook {
    teamA: CombatantInstance[];
    teamB: CombatantInstance[];
    addSlot: (side: 'A' | 'B') => void;
    removeSlot: (side: 'A' | 'B', instanceId: string) => void;
    updateSlot: (side: 'A' | 'B', instanceId: string, data: Partial<CombatantInstance>) => void;
    combatLog: { msg: string; color: string }[];
    isBattleRunning: boolean;
    battleSpeed: 1 | 2 | 4 | 8;
    setBattleSpeed: (speed: 1 | 2 | 4 | 8) => void;
    singleMatchReport: SingleMatchReport | null;
    bulkReport: BulkReport | null;
    isSearching: boolean;
    handleReset: () => void;
    runBulkSimulation: () => void;
    runAttackCycle: () => void;
    runCounterBuildSearch: () => void;
    getDerivedStats: (mercId: string | null, level: number, alloc: PrimaryStats) => DerivedStats | null;
}

const createEmptyCombatant = (): CombatantInstance => ({
    instanceId: `inst_${Math.random().toString(36).substr(2, 9)}`,
    mercenaryId: null,
    level: 25,
    allocatedStats: { str: 0, vit: 0, dex: 0, int: 0, luk: 0 },
    currentHp: 0,
    gauge: 0,
    dps: 0
});

export const useSimulation = (): SimulationHook => {
    const { state } = useGame();
    const [teamA, setTeamA] = useState<CombatantInstance[]>([createEmptyCombatant()]);
    const [teamB, setTeamB] = useState<CombatantInstance[]>([createEmptyCombatant()]);

    const [combatLog, setCombatLog] = useState<{msg: string, color: string}[]>([]);
    const [isBattleRunning, setIsBattleRunning] = useState(false);
    const [battleSpeed, setBattleSpeed] = useState<1 | 2 | 4 | 8>(1);
    const [singleMatchReport, setSingleMatchReport] = useState<SingleMatchReport | null>(null);
    const [bulkReport, setBulkReport] = useState<BulkReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);

    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);
    const battleSpeedRef = useRef<number>(1);
    const stopSearchRef = useRef(false);
    const matchStatsRef = useRef<{A: MatchStats, B: MatchStats, ticks: number}>({
        A: { totalDmg: 0, crits: 0, misses: 0, attacks: 0, evasions: 0 },
        B: { totalDmg: 0, crits: 0, misses: 0, attacks: 0, evasions: 0 },
        ticks: 0
    });

    useEffect(() => { battleSpeedRef.current = battleSpeed; }, [battleSpeed]);

    const getDerivedStats = (mercId: string | null, level: number, alloc: PrimaryStats) => {
        const merc = state.knownMercenaries.find(m => m.id === mercId);
        if (!merc) return null;
        const primary = mergePrimaryStats(merc.stats, alloc);
        const base = calculateDerivedStats(primary, level);
        const eqStats = (Object.values(merc.equipment) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean);
        return applyEquipmentBonuses(base, eqStats as any);
    };

    const addSlot = (side: 'A' | 'B') => {
        const setter = side === 'A' ? setTeamA : setTeamB;
        setter(prev => prev.length < MAX_SQUAD_SIZE ? [...prev, createEmptyCombatant()] : prev);
    };

    const removeSlot = (side: 'A' | 'B', instanceId: string) => {
        const setter = side === 'A' ? setTeamA : setTeamB;
        setter(prev => prev.length > 1 ? prev.filter(i => i.instanceId !== instanceId) : prev);
    };

    const updateSlot = (side: 'A' | 'B', instanceId: string, data: Partial<CombatantInstance>) => {
        const setter = side === 'A' ? setTeamA : setTeamB;
        setter(prev => prev.map(item => {
            if (item.instanceId !== instanceId) return item;
            const updated = { ...item, ...data };
            // Auto-calculate HP and DPS if dependencies changed
            if (data.mercenaryId !== undefined || data.level !== undefined || data.allocatedStats !== undefined) {
                const derived = getDerivedStats(updated.mercenaryId, updated.level, updated.allocatedStats);
                if (derived) {
                    updated.currentHp = derived.maxHp;
                    const merc = state.knownMercenaries.find(m => m.id === updated.mercenaryId);
                    const isMage = (merc!.stats.int + updated.allocatedStats.int) > (merc!.stats.str + updated.allocatedStats.str);
                    updated.dps = calculateExpectedDPS(derived, isMage ? 'MAGICAL' : 'PHYSICAL');
                }
            }
            return updated;
        }));
    };

    const addLog = (msg: string, color: string = 'text-stone-400') => {
        setCombatLog(prev => [{ msg, color }, ...prev].slice(0, 100));
    };

    const handleReset = () => {
        setIsBattleRunning(false); setIsSearching(false); stopSearchRef.current = true;
        if (battleInterval.current) clearInterval(battleInterval.current);

        const resetTeam = (team: CombatantInstance[]) => team.map(c => {
            const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
            return { ...c, currentHp: derived ? derived.maxHp : 0, gauge: 0, lastAttacker: false };
        });

        setTeamA(resetTeam);
        setTeamB(resetTeam);
        setCombatLog([{ msg: "Arena Reset. Squads ready.", color: "text-amber-500 font-bold" }]);
        setSingleMatchReport(null); setBulkReport(null);
    };

    const runBulkSimulation = () => {
        if (isSearching) return;
        setBulkReport(null);
        const rounds = 10000;
        let winA = 0;
        let totalAtksA = 0, totalAtksB = 0;
        let totalCritsA = 0, totalCritsB = 0;
        let totalEvasionsA = 0, totalEvasionsB = 0;

        const teamAData = teamA.filter(c => c.mercenaryId).map(c => ({
            derived: getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!,
            isMage: (state.knownMercenaries.find(m => m.id === c.mercenaryId)!.stats.int + c.allocatedStats.int) > (state.knownMercenaries.find(m => m.id === c.mercenaryId)!.stats.str + c.allocatedStats.str)
        }));
        const teamBData = teamB.filter(c => c.mercenaryId).map(c => ({
            derived: getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!,
            isMage: (state.knownMercenaries.find(m => m.id === c.mercenaryId)!.stats.int + c.allocatedStats.int) > (state.knownMercenaries.find(m => m.id === c.mercenaryId)!.stats.str + c.allocatedStats.str)
        }));

        if (teamAData.length === 0 || teamBData.length === 0) return;

        for (let i = 0; i < rounds; i++) {
            let hpsA = teamAData.map(d => d.derived.maxHp);
            let hpsB = teamBData.map(d => d.derived.maxHp);
            let gaugesA = teamAData.map(() => 0);
            let gaugesB = teamBData.map(() => 0);

            while (hpsA.some(h => h > 0) && hpsB.some(h => h > 0)) {
                // Find next actor
                teamAData.forEach((d, idx) => { if (hpsA[idx] > 0) gaugesA[idx] += d.derived.speed; });
                teamBData.forEach((d, idx) => { if (hpsB[idx] > 0) gaugesB[idx] += d.derived.speed; });

                const processTurn = (side: 'A' | 'B', idx: number) => {
                    const attackerData = side === 'A' ? teamAData[idx] : teamBData[idx];
                    const enemyHps = side === 'A' ? hpsB : hpsA;
                    const enemyTeam = side === 'A' ? teamBData : teamAData;

                    const livingEnemies = enemyHps.map((h, i) => h > 0 ? i : -1).filter(i => i !== -1);
                    if (livingEnemies.length === 0) return;

                    const targetIdx = livingEnemies[Math.floor(Math.random() * livingEnemies.length)];
                    const targetData = enemyTeam[targetIdx];

                    if (side === 'A') totalAtksA++; else totalAtksB++;

                    const res = calculateCombatResult(attackerData.derived, targetData.derived, attackerData.isMage ? 'MAGICAL' : 'PHYSICAL');
                    if (res.isHit) {
                        if (res.isCrit) { if (side === 'A') totalCritsA++; else totalCritsB++; }
                        enemyHps[targetIdx] = Math.max(0, enemyHps[targetIdx] - res.damage);
                    } else {
                        if (side === 'A') totalEvasionsB++; else totalEvasionsA++;
                    }
                };

                // Handle filled gauges
                const readyA = gaugesA.map((g, i) => g >= ACTION_THRESHOLD ? i : -1).filter(i => i !== -1);
                const readyB = gaugesB.map((g, i) => g >= ACTION_THRESHOLD ? i : -1).filter(i => i !== -1);

                if (readyA.length > 0 || readyB.length > 0) {
                    // Simple interleaved resolution
                    readyA.forEach(idx => { gaugesA[idx] -= ACTION_THRESHOLD; processTurn('A', idx); });
                    readyB.forEach(idx => { gaugesB[idx] -= ACTION_THRESHOLD; processTurn('B', idx); });
                }
            }
            if (hpsA.some(h => h > 0)) winA++;
        }

        setBulkReport({ 
            rounds, winA, winB: rounds - winA, 
            avgAtksA: totalAtksA / rounds, avgAtksB: totalAtksB / rounds, 
            avgCritsA: totalCritsA / rounds, avgCritsB: totalCritsB / rounds, 
            avgEvasionsA: totalEvasionsA / rounds, avgEvasionsB: totalEvasionsB / rounds 
        });
    };

    const runAttackCycle = () => {
        if (isBattleRunning) { 
            setIsBattleRunning(false); 
            if (battleInterval.current) clearInterval(battleInterval.current); 
            return; 
        }

        const validA = teamA.filter(c => c.mercenaryId);
        const validB = teamB.filter(c => c.mercenaryId);
        if (validA.length === 0 || validB.length === 0) return;

        setIsBattleRunning(true); setSingleMatchReport(null); setBulkReport(null);
        matchStatsRef.current = { A: { totalDmg: 0, crits: 0, misses: 0, attacks: 0, evasions: 0 }, B: { totalDmg: 0, crits: 0, misses: 0, attacks: 0, evasions: 0 }, ticks: 0 };

        battleInterval.current = setInterval(() => {
            const speedMult = battleSpeedRef.current; 
            matchStatsRef.current.ticks++;

            setTeamA(prev => {
                const next = [...prev];
                next.forEach(c => {
                    if (c.currentHp > 0) {
                        const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
                        if (derived) c.gauge += (derived.speed * 0.1 * speedMult);
                    }
                });
                return next;
            });

            setTeamB(prev => {
                const next = [...prev];
                next.forEach(c => {
                    if (c.currentHp > 0) {
                        const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
                        if (derived) c.gauge += (derived.speed * 0.1 * speedMult);
                    }
                });
                return next;
            });

            // Check for actors
            setTeamA(prevA => {
                setTeamB(prevB => {
                    const readyA = prevA.filter(c => c.gauge >= ACTION_THRESHOLD && c.currentHp > 0);
                    const readyB = prevB.filter(c => c.gauge >= ACTION_THRESHOLD && c.currentHp > 0);

                    const executeAttack = (att: CombatantInstance, side: 'A' | 'B') => {
                        const targets = (side === 'A' ? prevB : prevA).filter(c => c.currentHp > 0);
                        if (targets.length === 0) return;

                        const target = targets[Math.floor(Math.random() * targets.length)];
                        const attDerived = getDerivedStats(att.mercenaryId, att.level, att.allocatedStats)!;
                        const defDerived = getDerivedStats(target.mercenaryId, target.level, target.allocatedStats)!;
                        const merc = state.knownMercenaries.find(m => m.id === att.mercenaryId)!;
                        const isMage = (merc.stats.int + att.allocatedStats.int) > (merc.stats.str + att.allocatedStats.str);

                        const stats = side === 'A' ? matchStatsRef.current.A : matchStatsRef.current.B;
                        const enemyStats = side === 'A' ? matchStatsRef.current.B : matchStatsRef.current.A;

                        stats.attacks++;
                        att.gauge -= ACTION_THRESHOLD;
                        att.lastAttacker = true;
                        setTimeout(() => {
                            setTeamA(curr => curr.map(c => c.instanceId === att.instanceId ? { ...c, lastAttacker: false } : c));
                            setTeamB(curr => curr.map(c => c.instanceId === att.instanceId ? { ...c, lastAttacker: false } : c));
                        }, 100);

                        const res = calculateCombatResult(attDerived, defDerived, isMage ? 'MAGICAL' : 'PHYSICAL');
                        if (res.isHit) {
                            if (res.isCrit) stats.crits++;
                            stats.totalDmg += res.damage;
                            target.currentHp = Math.max(0, target.currentHp - res.damage);
                            addLog(`${merc.name} strikes ${target.mercenaryId ? state.knownMercenaries.find(m=>m.id===target.mercenaryId)!.name : 'Enemy'} for ${res.damage}${res.isCrit ? "!" : ""}`, side === 'A' ? "text-blue-300" : "text-red-300");
                        } else {
                            stats.misses++;
                            enemyStats.evasions++;
                            addLog(`${merc.name} missed!`, "text-stone-500 italic");
                        }
                    };

                    readyA.forEach(c => executeAttack(c, 'A'));
                    readyB.forEach(c => executeAttack(c, 'B'));

                    return [...prevB];
                });
                return [...prevA];
            });

            // Check end condition
            const aliveA = teamA.filter(c => c.mercenaryId && c.currentHp > 0).length;
            const aliveB = teamB.filter(c => c.mercenaryId && c.currentHp > 0).length;

            if (aliveA === 0 || aliveB === 0) {
                setIsBattleRunning(false); 
                clearInterval(battleInterval.current!);
                setSingleMatchReport({ 
                    winner: aliveA > 0 ? 'A' : 'B', 
                    durationTicks: matchStatsRef.current.ticks, 
                    statsA: { ...matchStatsRef.current.A }, 
                    statsB: { ...matchStatsRef.current.B }, 
                    analysis: ["Battle concluded. Team " + (aliveA > 0 ? "A" : "B") + " standing."] 
                });
            }
        }, 40);
    };

    const runCounterBuildSearch = () => {
        // Limited to 1v1 for complexity, searching for Slot 0 counter
        if (!teamA[0].mercenaryId || !teamB[0].mercenaryId || isSearching) return;
        handleReset(); setIsSearching(true); stopSearchRef.current = false;

        const SIM_LEVEL = teamA[0].level;
        const SIM_POINTS = (SIM_LEVEL - 1) * 3;
        const targetD = getDerivedStats(teamA[0].mercenaryId, teamA[0].level, teamA[0].allocatedStats)!;
        const targetP = mergePrimaryStats(state.knownMercenaries.find(m => m.id === teamA[0].mercenaryId)!.stats, teamA[0].allocatedStats);

        const POP_SIZE = 50;
        const GENERATIONS = 30;
        const SEARCH_KEYS = ['str', 'vit', 'dex', 'luk'] as (keyof PrimaryStats)[];

        let population = Array.from({ length: POP_SIZE }, () => {
            const stats = { str: 0, vit: 0, dex: 0, int: 0, luk: 0 };
            for (let i = 0; i < SIM_POINTS; i++) stats[SEARCH_KEYS[Math.floor(Math.random() * SEARCH_KEYS.length)]]++;
            return { stats, fitness: 0 };
        });

        let currentGen = 0;
        addLog(`Analyzing Squad Slot 1 vulnerability...`, "text-indigo-400 font-bold");

        const runGeneration = () => {
            if (stopSearchRef.current || currentGen >= GENERATIONS) {
                setIsSearching(false);
                addLog(`Strategic scan complete.`, "text-white font-bold border-t border-stone-700 mt-1 pt-1");
                return;
            }

            population.forEach(ind => {
                const combined = mergePrimaryStats(state.knownMercenaries.find(m => m.id === teamB[0].mercenaryId)!.stats, ind.stats);
                const dStats = applyEquipmentBonuses(calculateDerivedStats(combined, SIM_LEVEL), (Object.values(state.knownMercenaries.find(m => m.id === teamB[0].mercenaryId)!.equipment) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean) as any);

                // Simplified simulation for fitness
                let wins = 0;
                for(let r=0; r<100; r++){
                    let hA = targetD.maxHp, hB = dStats.maxHp, gA=0, gB=0;
                    while(hA>0 && hB>0){
                        gA += targetD.speed; gB += dStats.speed;
                        if(gB >= 1000) { gB-=1000; const res=calculateCombatResult(dStats, targetD, 'PHYSICAL'); if(res.isHit) hA-=res.damage; }
                        if(hA<=0) break;
                        if(gA >= 1000) { gA-=1000; const res=calculateCombatResult(targetD, dStats, 'PHYSICAL'); if(res.isHit) hB-=res.damage; }
                    }
                    if(hB > 0) wins++;
                }
                ind.fitness = wins / 100;
            });

            population.sort((a, b) => b.fitness - a.fitness);
            const newPop = population.slice(0, 10);
            while (newPop.length < POP_SIZE) {
                const stats = { str: 0, vit: 0, dex: 0, int: 0, luk: 0 };
                for (let i = 0; i < SIM_POINTS; i++) stats[SEARCH_KEYS[Math.floor(Math.random() * SEARCH_KEYS.length)]]++;
                newPop.push({ stats, fitness: 0 });
            }
            population = newPop;
            currentGen++;
            setTimeout(runGeneration, 10);
        };
        runGeneration();
    };

    return {
        teamA, teamB, addSlot, removeSlot, updateSlot,
        combatLog, isBattleRunning, battleSpeed, setBattleSpeed,
        singleMatchReport, bulkReport, isSearching,
        handleReset, runBulkSimulation, runAttackCycle, runCounterBuildSearch,
        getDerivedStats
    };
};

import React, { useState, useRef, useCallback, useMemo } from 'react';
import { useGame } from '../../../context/GameContext';
import { useSimulation, CombatantInstance } from '../../../hooks/useSimulation';
import { Mercenary } from '../../../models/Mercenary';
import { DerivedStats, PrimaryStats } from '../../../models/Stats';
import { Sword, Shield, Activity, User, Play, RefreshCw, ScrollText, Crosshair, Target, Wind, FastForward, Brain, X, ChevronUp, ChevronDown, Package, Plus, Trash2, Trophy } from 'lucide-react';

const ACTION_THRESHOLD = 1000;

const HoldButton = ({ onAction, disabled, className, children }: React.PropsWithChildren<{ onAction: () => void, disabled?: boolean, className?: string }>) => {
    const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
    const delayRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const start = useCallback((e: React.MouseEvent | React.TouchEvent) => {
        if (disabled) return;
        if ('preventDefault' in e) e.preventDefault();
        onAction();
        delayRef.current = setTimeout(() => { timerRef.current = setInterval(() => { onAction(); }, 50); }, 300);
    }, [onAction, disabled]);
    const stop = useCallback(() => { if (timerRef.current) clearInterval(timerRef.current); if (delayRef.current) clearTimeout(delayRef.current); }, []);
    return <button onMouseDown={start} onMouseUp={stop} onMouseLeave={stop} onTouchStart={start} onTouchEnd={stop} disabled={disabled} className={className}>{children}</button>;
};

const StatBox = ({ label, value, icon, color = "text-stone-400" }: { label: string, value: number | string, icon: React.ReactNode, color?: string }) => (
    <div className="bg-stone-800/30 border border-stone-800/40 p-0.5 md:p-1 rounded flex items-center justify-between min-w-0">
        <span className={`text-[6px] md:text-[8px] font-black uppercase flex items-center gap-0.5 ${color} truncate mr-1`}>{icon} <span className="hidden xs:inline">{label}</span></span>
        <span className="font-mono text-[8px] md:text-[10px] font-bold text-stone-200 shrink-0">{value}</span>
    </div>
);

const getArchetype = (p: PrimaryStats) => {
    const max = Math.max(p.str, p.vit, p.dex, p.int, p.luk);
    if (p.str === max) return { label: 'Berserker', color: 'bg-orange-600', icon: <Sword className="w-2 h-2 md:w-2.5 md:h-2.5"/> };
    if (p.vit === max) return { label: 'Guardian', color: 'bg-red-700', icon: <Shield className="w-2 h-2 md:w-2.5 md:h-2.5"/> };
    if (p.dex === max) return { label: 'Assassin', color: 'bg-emerald-600', icon: <Wind className="w-2 h-2 md:w-2.5 md:h-2.5"/> };
    if (p.int === max) return { label: 'Scholar', color: 'bg-blue-600', icon: <Brain className="w-2 h-2 md:w-2.5 md:h-2.5"/> };
    if (p.luk === max) return { label: 'Gambler', color: 'bg-pink-600', icon: <Target className="w-2 h-2 md:w-2.5 md:h-2.5"/> };
    return { label: 'Adept', color: 'bg-stone-600', icon: <Activity className="w-2 h-2 md:w-2.5 md:h-2.5"/> };
};

const CombatantSlot = ({ 
    side, combatant, mercenary, derived, onSelect, onUpdate, onRemove, disabled 
}: { 
    side: 'LEFT' | 'RIGHT', combatant: CombatantInstance, mercenary: Mercenary | null, derived: DerivedStats | null, onSelect: () => void, onUpdate: (data: Partial<CombatantInstance>) => void, onRemove: () => void, disabled?: boolean 
}) => {
    const hpPercent = derived ? (combatant.currentHp / derived.maxHp) * 100 : 0;
    const gaugePercent = Math.min(100, (combatant.gauge / ACTION_THRESHOLD) * 100);
    const totalPoints = (combatant.level - 1) * 3;
    const usedPoints = Object.values(combatant.allocatedStats).reduce((a, b) => a + b, 0);
    const availablePoints = Math.max(0, totalPoints - usedPoints);

    const mergedStats = mercenary ? {
        str: mercenary.stats.str + combatant.allocatedStats.str,
        vit: mercenary.stats.vit + combatant.allocatedStats.vit,
        dex: mercenary.stats.dex + combatant.allocatedStats.dex,
        int: mercenary.stats.int + combatant.allocatedStats.int,
        luk: mercenary.stats.luk + combatant.allocatedStats.luk,
    } : null;

    const archetype = mergedStats ? getArchetype(mergedStats) : null;
    const isMage = mergedStats ? mergedStats.int > mergedStats.str : false;
    const weaponAtk = derived ? (isMage ? derived.magicalAttack : derived.physicalAttack) : 0;

    return (
        <div className={`flex flex-col gap-1 p-2 md:p-3 bg-stone-900 border transition-all duration-300 rounded-xl relative overflow-hidden ${side === 'LEFT' ? 'border-blue-900/40' : 'border-red-900/40'} ${combatant.lastAttacker ? 'scale-[1.02] ring-2 ring-amber-500 z-10' : 'hover:border-stone-700'} ${disabled ? 'opacity-50 pointer-events-none' : ''} ${mercenary && combatant.currentHp <= 0 ? 'grayscale opacity-30' : ''}`}>
            {mercenary && derived ? (
                <div className="flex flex-col gap-1">
                    {/* Compact Header */}
                    <div className={`flex items-center justify-between gap-1 ${side === 'RIGHT' ? 'flex-row-reverse text-right' : ''}`}>
                         <div className={`flex items-center gap-1.5 md:gap-2 ${side === 'RIGHT' ? 'flex-row-reverse' : ''} min-w-0`}>
                            <div onClick={onSelect} className="w-8 h-8 md:w-10 md:h-10 bg-stone-800 rounded-lg border border-stone-700 flex items-center justify-center text-base md:text-xl shadow-inner shrink-0 cursor-pointer hover:border-amber-500 transition-colors">{mercenary.icon}</div>
                            <div className="min-w-0 flex flex-col justify-center">
                                <div className="flex items-center gap-1 truncate">
                                    <h3 className="text-[9px] md:text-xs font-black text-stone-200 truncate leading-none uppercase">{mercenary.name.split(' ')[0]}</h3>
                                    {archetype && (
                                        <span className={`text-[5px] md:text-[7px] px-1 rounded-full text-white font-black uppercase flex items-center gap-0.5 ${archetype.color} shrink-0`}>
                                            {archetype.label}
                                        </span>
                                    )}
                                </div>
                                <div className={`flex items-center gap-1 text-[7px] md:text-[9px] font-bold text-amber-600 mt-0.5 ${side === 'RIGHT' ? 'justify-end' : ''}`}>
                                    <div className="flex items-center bg-stone-950 px-1 rounded border border-amber-900/20">
                                        <HoldButton onAction={() => onUpdate({ level: Math.max(1, combatant.level - 1) })} className="hover:text-white px-0.5 text-[8px] font-black">-</HoldButton>
                                        <span className="mx-0.5 select-none font-mono tracking-tighter">LV{combatant.level}</span>
                                        <HoldButton onAction={() => onUpdate({ level: combatant.level + 1 })} className="hover:text-white px-0.5 text-[8px] font-black">+</HoldButton>
                                    </div>
                                    <span className="text-stone-500 font-mono text-[7px] md:text-[8px] uppercase">{combatant.dps} DPS</span>
                                </div>
                            </div>
                        </div>
                        <button onClick={onRemove} className="p-1 hover:text-red-500 text-stone-700 transition-colors"><Trash2 className="w-3 h-3" /></button>
                    </div>

                    {/* Integrated Micro Vitals */}
                    <div className="space-y-0.5 shrink-0">
                        <div className="h-0.5 md:h-1 bg-stone-950 rounded-full overflow-hidden border border-stone-800/50">
