                        </div>
                    </div>

                    {/* Slim Attribute Bar */}
                    <div className="bg-stone-950/60 p-1 rounded-lg border border-stone-800/50 flex flex-col gap-1">
                        <div className="grid grid-cols-5 gap-0.5 md:gap-1">
                            {[
                                { label: 'STR', key: 'str' as const, color: 'text-orange-400' },
                                { label: 'VIT', key: 'vit' as const, color: 'text-red-400' },
                                { label: 'DEX', key: 'dex' as const, color: 'text-emerald-400' },
                                { label: 'INT', key: 'int' as const, color: 'text-blue-400' },
                                { label: 'LUK', key: 'luk' as const, color: 'text-pink-400' },
                            ].map(s => (
                                <div key={s.label} className="flex flex-col items-center flex-1 bg-stone-900/80 rounded border border-stone-800/50 py-0.5">
                                    <span className={`text-[5px] md:text-[7px] font-black ${s.color}`}>{s.label}</span>
                                    <div className="flex items-center gap-0.5">
                                        <HoldButton onAction={() => onUpdate({ allocatedStats: {...combatant.allocatedStats, [s.key]: Math.max(0, combatant.allocatedStats[s.key] - 1)} })} disabled={combatant.allocatedStats[s.key] <= 0} className="text-stone-600 hover:text-red-400 transition-colors disabled:opacity-0"><ChevronDown className="w-2 h-2" /></HoldButton>
                                        <span className="text-[8px] md:text-[9px] font-mono font-black text-stone-200 leading-none select-none">{mercenary.stats[s.key] + combatant.allocatedStats[s.key]}</span>
                                        <HoldButton onAction={() => onUpdate({ allocatedStats: {...combatant.allocatedStats, [s.key]: combatant.allocatedStats[s.key] + 1} })} disabled={availablePoints <= 0} className="text-amber-500 hover:text-white transition-colors disabled:opacity-0"><ChevronUp className="w-2 h-2" /></HoldButton>
                                    </div>
                                </div>
                            ))}
