                    <div className="bg-stone-950/60 p-1.5 rounded-lg border border-stone-800/50 flex flex-col gap-1.5 flex-1 min-h-0">
                        <div className="grid grid-cols-5 gap-1 md:gap-1.5 h-full">
                            {[
